(function(global){
  'use strict';
  var languages = {
    python: function(text){
      return text
        .replace(/(&)/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
        .replace(/(^|\s)(#.*)$/gm,'$1<span class="hl-comment">$2</span>')
        .replace(/\b(def|class|import|from|return|if|elif|else|for|while|try|except|with|as|lambda|True|False|None)\b/g,'<span class="hl-keyword">$1</span>');
    },
    javascript: function(text){
      return text
        .replace(/(&)/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
        .replace(/(\/\/.*$)/gm,'<span class="hl-comment">$1</span>')
        .replace(/\b(function|const|let|var|return|if|else|for|while|class|new|try|catch|async|await|import|from|export|default)\b/g,'<span class="hl-keyword">$1</span>');
    },
    html: function(text){
      return text
        .replace(/(&)/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
        .replace(/(&lt;\/?[a-zA-Z0-9:-]+)([^&]*?)(?=&gt;)/g,'<span class="hl-tag">$1</span>$2')
        .replace(/(["'])(.*?)\1/g,'<span class="hl-string">$1$2$1</span>');
    },
    css: function(text){
      return text
        .replace(/(&)/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
        .replace(/([.#]?[a-zA-Z0-9_-]+)(\s*\{)/g,'<span class="hl-selector">$1</span>$2')
        .replace(/(:)([^;]+)(;)/g,'$1<span class="hl-property">$2</span>$3');
    },
    json: function(text){
      return text
        .replace(/(&)/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
        .replace(/("(?:\\.|[^"\\])*"\s*:)/g,'<span class="hl-keyword">$1</span>');
    },
    plaintext: function(text){
      return text.replace(/(&)/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    }
  };
  function highlightElement(el){
    var lang = el.className.replace(/language-/,'').trim() || 'plaintext';
    var formatter = languages[lang] || languages.plaintext;
    el.innerHTML = formatter(el.textContent || '');
  }
  global.hljs = { highlightElement: highlightElement };
})(window);